export const sections = [
  {
    "id": "installation",
    "title": "Installation",
    "order": 1,
    "html": "<h2>Installation</h2>\n<p>Install lit-router via npm. The package has no external dependencies.</p>\n<copy-console content=\"npm install lit-router\"></copy-console>\n<h2>Basic Setup</h2>\n<p>Create a <code>Router</code> instance inside your LitElement. <code>Router</code> is a <a href=\"https://lit.dev/docs/composition/controllers/\">Reactive Controller</a> — it manages route matching and triggers re-renders when the URL changes.</p>\n<pre><code class=\"language-typescript\">import { LitElement, html } from &#39;lit&#39;;\nimport Router from &#39;lit-router&#39;;\n\nclass MyApp extends LitElement {\n  _router = new Router(this, [\n    { path: &#39;/&#39;, render: () =&gt; html`&lt;home-page&gt;&lt;/home-page&gt;` },\n    { path: &#39;/users/:id&#39;, render: ({ params }) =&gt;\n      html`&lt;user-profile id=${params.id}&gt;&lt;/user-profile&gt;` },\n  ]);\n\n  render() {\n    return html`\n      &lt;nav&gt;\n        &lt;a href=&quot;/&quot;&gt;Home&lt;/a&gt;\n        &lt;a href=&quot;/users/123&quot;&gt;Profile&lt;/a&gt;\n      &lt;/nav&gt;\n      &lt;main&gt;\n        ${this._router.outlet()}\n      &lt;/main&gt;\n    `;\n  }\n}\n\ncustomElements.define(&#39;my-app&#39;, MyApp);\n</code></pre>\n<p>The <code>Router</code> intercepts all <code>&lt;a&gt;</code> clicks on <code>window</code> in capture phase. Same-origin links that are not <code>defaultPrevented</code>, not <code>router-ignore</code>, and have no modifier keys or <code>download</code> attribute are handled automatically — no event listeners needed. The click calls <code>e.preventDefault()</code> and <code>router.navigate()</code> internally.</p>\n<h2>Rendering Outlets</h2>\n<p>To render the current matched route, call the controller&#39;s <code>outlet()</code> method inside the host LitElement&#39;s <code>render</code> function:\n<code>outlet()</code> renders the component matched by the current URL. The <code>render</code> callback receives a context object with <code>{ params, extraParams, searchParams, hash, route }</code>. Dynamic segments like <code>:id</code> are available via <code>params.id</code>.</p>\n<pre><code class=\"language-javascript\">render() {\n  return html`&lt;main&gt;${this._router.outlet()}&lt;/main&gt;`;\n}\n</code></pre>\n<p>This generates a <code>&lt;lit-router-outlet&gt;</code> wrapper that propagates lifecycle events down to nested child routes automatically.</p>\n"
  },
  {
    "id": "anchor-links",
    "title": "Anchor Links",
    "order": 2,
    "html": "<h2>Anchor Links</h2>\n<p>The <code>Router</code> intercepts all <code>&lt;a&gt;</code> clicks automatically. A single event listener is installed on <code>window</code> in capture phase — no per-link wiring, no event delegation boilerplate.</p>\n<p>When a click meets the interception conditions, the Router calls <code>e.preventDefault()</code> and <code>router.navigate()</code>, then <code>window.scrollTo(0, 0)</code>. The page does not reload.</p>\n<h3>Interception Conditions</h3>\n<p>All of the following must be true for the Router to take over. If any condition fails, the browser handles the click normally.</p>\n<table>\n<thead>\n<tr>\n<th>Condition</th>\n<th>Why</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>e.defaultPrevented</code> is <code>false</code></td>\n<td>Another listener already consumed the event</td>\n</tr>\n<tr>\n<td>The composed path contains an <code>&lt;a&gt;</code> element</td>\n<td>Clicks on nested children of <code>&lt;a&gt;</code> still work</td>\n</tr>\n<tr>\n<td>The anchor has an <code>href</code> attribute</td>\n<td>Links without <code>href</code> are not navigable</td>\n</tr>\n<tr>\n<td><code>e.button === 0</code></td>\n<td>Left-click only; middle-click and right-click open new tabs</td>\n</tr>\n<tr>\n<td>No modifier keys (Alt, Ctrl, Meta, Shift)</td>\n<td>User intent is to open in new tab/window</td>\n</tr>\n<tr>\n<td>No <code>download</code> attribute</td>\n<td>Downloads are handled by the browser</td>\n</tr>\n<tr>\n<td>No <code>router-ignore</code> attribute</td>\n<td>Explicit opt-out from router handling</td>\n</tr>\n<tr>\n<td>Target is not <code>_blank</code>, <code>_parent</code>, or <code>_top</code></td>\n<td>Cross-context navigation is browser territory</td>\n</tr>\n<tr>\n<td>Same origin as <code>window.location</code></td>\n<td>External domains load normally</td>\n</tr>\n</tbody></table>\n<h3>Basic Usage</h3>\n<p>Zero configuration. Drop <code>&lt;a&gt;</code> elements anywhere in your templates.</p>\n<pre><code class=\"language-typescript\">import { LitElement, html } from &#39;lit&#39;;\nimport Router from &#39;lit-router&#39;;\n\nclass App extends LitElement {\n  _router = new Router(this, [\n    { path: &#39;/&#39;,       render: () =&gt; html`&lt;home-page&gt;&lt;/home-page&gt;` },\n    { path: &#39;/users&#39;,  render: () =&gt; html`&lt;users-page&gt;&lt;/users-page&gt;` },\n    { path: &#39;/about&#39;,  render: () =&gt; html`&lt;about-page&gt;&lt;/about-page&gt;` },\n    { path: &#39;*&#39;,       render: () =&gt; html`&lt;not-found&gt;&lt;/not-found&gt;` },\n  ]);\n\n  render() {\n    return html`\n      &lt;nav&gt;\n        &lt;a href=&quot;/&quot;&gt;Home&lt;/a&gt;\n        &lt;a href=&quot;/users&quot;&gt;Users&lt;/a&gt;\n        &lt;a href=&quot;/about&quot;&gt;About&lt;/a&gt;\n      &lt;/nav&gt;\n      &lt;main&gt;${this._router.outlet()}&lt;/main&gt;\n    `;\n  }\n}\n</code></pre>\n<p>Each click navigates to the target route, updates the URL bar, and scrolls to the top — no page reload, no explicit event listeners.</p>\n<h3>Links with Query and Hash</h3>\n<p>The Router parses <code>?query</code> and <code>#hash</code> directly from the <code>href</code> attribute.</p>\n<pre><code class=\"language-html\">&lt;a href=&quot;/search?q=lit+router&quot;&gt;Search results for &quot;lit router&quot;&lt;/a&gt;\n&lt;a href=&quot;/docs#lifecycle&quot;&gt;Jump to lifecycle section&lt;/a&gt;\n</code></pre>\n<p>The first link calls <code>router.navigate(&quot;/search&quot;, { searchParams: { q: &quot;lit router&quot; } })</code>. The second calls <code>router.navigate(&quot;/docs&quot;, { hash: &quot;lifecycle&quot; })</code>. Both are accessible in the target route&#39;s <code>render</code> callback via <code>searchParams</code> and <code>hash</code>.</p>\n<h3>Excluding Links with <code>router-ignore</code></h3>\n<p>Add the <code>router-ignore</code> attribute to any <code>&lt;a&gt;</code> that should bypass the Router. The browser handles the click normally — external navigation, download, or full page reload.</p>\n<pre><code class=\"language-html\">&lt;!-- External domains --&gt;\n&lt;a router-ignore href=&quot;https://github.com/lit-router&quot;&gt;View on GitHub&lt;/a&gt;\n\n&lt;!-- Downloads --&gt;\n&lt;a router-ignore href=&quot;/api/reports/export&quot; download&gt;Download Report&lt;/a&gt;\n\n&lt;!-- Opening in a new tab (handled by target attribute automatically) --&gt;\n&lt;a href=&quot;/users&quot; target=&quot;_blank&quot;&gt;Users in new tab&lt;/a&gt;\n</code></pre>\n<p>The <code>target</code> attribute with <code>_blank</code> already bypasses the Router — you don&#39;t need <code>router-ignore</code> for new-tab links. Use <code>router-ignore</code> for same-origin links that should NOT go through the router: downloads, API endpoints that return files, or links handled by a third-party script.</p>\n<h3>Hash Links Within the Same Page</h3>\n<p>Links that point to <code>#section</code> on the current page need <code>router-ignore</code>. Without it, the Router intercepts the click, calls <code>navigate()</code>, and scrolls to the top — overriding the browser&#39;s native scroll-to-anchor behavior.</p>\n<pre><code class=\"language-html\">&lt;!-- Wrong: Router intercepts, navigates, scrolls to top --&gt;\n&lt;a href=&quot;#faq&quot;&gt;Frequently Asked Questions&lt;/a&gt;\n\n&lt;!-- Correct: Browser scrolls to the #faq element --&gt;\n&lt;a router-ignore href=&quot;#faq&quot;&gt;Frequently Asked Questions&lt;/a&gt;\n</code></pre>\n<p>Hash-based navigation within a single page is a scroll operation, not a route change. Let the browser handle it.</p>\n<h3>Error Handling</h3>\n<p>When an anchor click triggers a navigation that fails, the Router distinguishes two error types:</p>\n<ul>\n<li><p><strong><code>InvalidNavigationError</code></strong> — swallowed silently. This covers cancelled navigations (enter/leave returned <code>false</code>), missing routes, and invalid push attempts. The page stays where it is.</p>\n</li>\n<li><p><strong>Any other error</strong> — dispatched as <code>RouterNavigationErrorEvent</code> (event name <code>&quot;lit-router-error&quot;</code>) on the <code>&lt;a&gt;</code> element, then re-thrown in a microtask for global error telemetry.</p>\n</li>\n</ul>\n<pre><code class=\"language-typescript\">render() {\n  return html`\n    &lt;nav @lit-router-error=${this._onLinkError}&gt;\n      &lt;a href=&quot;/&quot;&gt;Home&lt;/a&gt;\n      &lt;a href=&quot;/broken-route&quot;&gt;Broken Link&lt;/a&gt;\n    &lt;/nav&gt;\n  `;\n}\n\n_onLinkError(e) {\n  console.error(&#39;Link navigation failed:&#39;, e.detail.error.message);\n  // Show a toast, redirect, or log to telemetry\n}\n</code></pre>\n<p>The event bubbles, so a single listener on a parent element covers all descendant links. The <code>detail</code> object contains <code>{ url, error }</code>.</p>\n<h3>Programmatic vs Anchor Navigation</h3>\n<table>\n<thead>\n<tr>\n<th></th>\n<th><code>&lt;a href=&quot;/users&quot;&gt;</code></th>\n<th><code>this.nav.navigate(&quot;/users&quot;)</code></th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Trigger</td>\n<td>User click on an anchor</td>\n<td>Any code path (button, timeout, response handler)</td>\n</tr>\n<tr>\n<td>URL bar</td>\n<td><code>history.pushState</code></td>\n<td><code>history.pushState</code></td>\n</tr>\n<tr>\n<td>Scroll</td>\n<td><code>scrollTo(0, 0)</code> automatically</td>\n<td>Manual — you control when and where</td>\n</tr>\n<tr>\n<td>Error handling</td>\n<td><code>@lit-router-error</code> event on the anchor</td>\n<td><code>try/catch</code> around <code>await</code></td>\n</tr>\n<tr>\n<td>Cancellation</td>\n<td>Not applicable</td>\n<td>Can await the promise to confirm success</td>\n</tr>\n</tbody></table>\n<p>Use anchor links for declarative navigation in templates. Use <code>navigate()</code> for navigation triggered by logic — form submissions, redirects after async operations, or programmatic flows where you need to await the result.</p>\n"
  },
  {
    "id": "advanced-route-matching",
    "title": "Route Matching",
    "order": 3,
    "html": "<h2>Route Matching</h2>\n<p>lit-router assigns a numeric score to every route at construction time. Routes are sorted descending by score, so the most specific route is tried first — order of definition does not affect matching.</p>\n<h3>Path Pattern Reference</h3>\n<table>\n<thead>\n<tr>\n<th>Pattern</th>\n<th>Matches</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>/about</code></td>\n<td>Static segment, exact literal match</td>\n</tr>\n<tr>\n<td><code>:param</code></td>\n<td>Single segment, non-slash chars</td>\n</tr>\n<tr>\n<td><code>:param?</code></td>\n<td>Zero or one optional segment</td>\n</tr>\n<tr>\n<td><code>*</code></td>\n<td>Zero or more trailing segments</td>\n</tr>\n<tr>\n<td><code>:param*</code></td>\n<td>Named capture of tail</td>\n</tr>\n</tbody></table>\n<h3>Catch-all Routes</h3>\n<p>A standalone <code>*</code> matches any URL not handled by previous routes. Because wildcards score lowest, more specific routes naturally win.</p>\n<pre><code class=\"language-typescript\">class App extends LitElement {\n  _router = new Router(this, [\n    { path: &#39;/&#39;,          render: () =&gt; html`&lt;home-page&gt;&lt;/home-page&gt;` },\n    { path: &#39;/users&#39;,     render: () =&gt; html`&lt;users-page&gt;&lt;/users-page&gt;` },\n    { path: &#39;/users/:id&#39;, render: ({ params }) =&gt;\n      html`&lt;user-page id=${params.id}&gt;&lt;/user-page&gt;` },\n    { path: &#39;/admin/*&#39;,   render: () =&gt; html`&lt;admin-layout&gt;&lt;/admin-layout&gt;` },\n    { path: &#39;*&#39;,          render: () =&gt; html`&lt;not-found&gt;&lt;/not-found&gt;` },\n  ]);\n}\n</code></pre>\n<p><code>/users</code> matches the static route, not the dynamic one. <code>/users/42</code> matches the dynamic route. <code>/admin/settings/users</code> matches the wildcard prefix. <code>/unknown</code> matches the catch-all.</p>\n<p>The <code>*</code> can appear anywhere in the definition array — the scorer deprioritizes it regardless of position.</p>\n<h3>Route Names</h3>\n<p>Assign a <code>name</code> to routes for debugging or for use with the <code>Navigation</code> controller&#39;s <code>routeName</code> property:</p>\n<pre><code class=\"language-typescript\">{ path: &#39;/dashboard&#39;, name: &#39;dashboard&#39;, render: () =&gt; html`&lt;dashboard-page&gt;&lt;/dashboard-page&gt;` }\n\n// In a child component:\n// this.nav.routeName === &#39;dashboard&#39;\n</code></pre>\n<h2>Scoring in Practice</h2>\n<p>The scoring formula rewards specificity. Static segments score highest, then dynamic parameters, then wildcards. Below are navigation scenarios that show which route wins and why.</p>\n<h4>Static beats dynamic for the same prefix</h4>\n<pre><code class=\"language-typescript\">const _router = new Router(this, [\n  { path: &#39;/orders/list&#39;, render: () =&gt; html`&lt;order-list&gt;&lt;/order-list&gt;` },\n  { path: &#39;/orders/:id&#39;,  render: ({ params }) =&gt;\n    html`&lt;order-detail id=${params.id}&gt;&lt;/order-detail&gt;` },\n]);\n</code></pre>\n<table>\n<thead>\n<tr>\n<th>URL</th>\n<th>Matches</th>\n<th>Because</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>/orders/list</code></td>\n<td><code>order-list</code></td>\n<td><code>/orders/list</code> has 2 static segments vs <code>/orders/:id</code> with 1 static + 1 dynamic. The all-static route scores higher</td>\n</tr>\n<tr>\n<td><code>/orders/982</code></td>\n<td><code>order-detail</code></td>\n<td>Nothing else matches the static route. <code>:id</code> captures <code>&quot;982&quot;</code></td>\n</tr>\n<tr>\n<td><code>/orders/list/items</code></td>\n<td>nothing</td>\n<td>Neither route matches. The static route requires an exact match; the dynamic route expects only one segment after <code>/orders/</code></td>\n</tr>\n</tbody></table>\n<h4>Deep routes outscore shallow ones</h4>\n<pre><code class=\"language-typescript\">const _router = new Router(this, [\n  { path: &#39;/blog/:slug&#39;,        render: ({ params }) =&gt;\n    html`&lt;blog-post slug=${params.slug}&gt;&lt;/blog-post&gt;` },\n  { path: &#39;/blog/:year/:month&#39;, render: ({ params }) =&gt;\n    html`&lt;blog-archive year=${params.year} month=${params.month}&gt;&lt;/blog-archive&gt;` },\n]);\n</code></pre>\n<table>\n<thead>\n<tr>\n<th>URL</th>\n<th>Matches</th>\n<th>Because</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>/blog/my-post</code></td>\n<td><code>blog-post</code></td>\n<td>Only <code>:slug</code> can match a single segment. <code>/blog/:year/:month</code> requires two segments</td>\n</tr>\n<tr>\n<td><code>/blog/2024/03</code></td>\n<td><code>blog-archive</code></td>\n<td>Three segments total. The deeper route (<code>/blog/:year/:month</code>) has higher depth (+1 per segment) and scores above <code>/blog/:slug</code> because <code>depth × 1</code> breaks the tie after static segments are counted</td>\n</tr>\n</tbody></table>\n<h4>Dynamic routes never beat static siblings</h4>\n<pre><code class=\"language-typescript\">const _router = new Router(this, [\n  { path: &#39;/:section&#39;,   render: ({ params }) =&gt;\n    html`&lt;section-page name=${params.section}&gt;&lt;/section-page&gt;` },\n  { path: &#39;/settings&#39;,   render: () =&gt; html`&lt;settings-page&gt;&lt;/settings-page&gt;` },\n  { path: &#39;/:section/*&#39;, render: ({ params }) =&gt;\n    html`&lt;section-layout section=${params.section}&gt;&lt;/section-layout&gt;` },\n]);\n</code></pre>\n<table>\n<thead>\n<tr>\n<th>URL</th>\n<th>Matches</th>\n<th>Because</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>/settings</code></td>\n<td><code>settings-page</code></td>\n<td>Static always outranks dynamic. Even though <code>/:section</code> could capture <code>&quot;settings&quot;</code>, the static route <code>/settings</code> scores ~1001 vs ~101</td>\n</tr>\n<tr>\n<td><code>/dashboard</code></td>\n<td><code>section-page</code></td>\n<td>No static route matches <code>dashboard</code>. <code>:section</code> captures <code>&quot;dashboard&quot;</code>. The wildcard <code>/:section/*</code> also matches but scores lower</td>\n</tr>\n<tr>\n<td><code>/dashboard/widgets</code></td>\n<td><code>section-layout</code></td>\n<td><code>:section</code> captures <code>&quot;dashboard&quot;</code>, wildcard <code>*</code> captures <code>/widgets</code>. Neither <code>:section</code> (which needs exactly one segment) nor <code>settings</code> (static mismatch) can match</td>\n</tr>\n</tbody></table>\n<h4>Wildcard is always last resort</h4>\n<pre><code class=\"language-typescript\">const _router = new Router(this, [\n  { path: &#39;/admin&#39;,      render: () =&gt; html`&lt;admin-dashboard&gt;&lt;/admin-dashboard&gt;` },\n  { path: &#39;/admin/*&#39;,    render: () =&gt; html`&lt;admin-layout&gt;&lt;/admin-layout&gt;` },\n  { path: &#39;/:page&#39;,      render: ({ params }) =&gt;\n    html`&lt;cms-page name=${params.page}&gt;&lt;/cms-page&gt;` },\n  { path: &#39;*&#39;,           render: () =&gt; html`&lt;not-found&gt;&lt;/not-found&gt;` },\n]);\n</code></pre>\n<table>\n<thead>\n<tr>\n<th>URL</th>\n<th>Matches</th>\n<th>Because</th>\n</tr>\n</thead>\n<tbody><tr>\n<td><code>/admin</code></td>\n<td><code>admin-dashboard</code></td>\n<td>Exact static match scores highest. <code>/admin/*</code> also matches but has a wildcard penalty</td>\n</tr>\n<tr>\n<td><code>/admin/users/42</code></td>\n<td><code>admin-layout</code></td>\n<td><code>/admin/*</code> captures the tail. The static <code>/admin</code> doesn&#39;t match because there are more segments. The dynamic <code>/:page</code> doesn&#39;t match because it expects exactly one segment</td>\n</tr>\n<tr>\n<td><code>/pricing</code></td>\n<td><code>cms-page</code></td>\n<td>No static match for <code>pricing</code>. <code>:page</code> captures it. <code>*</code> also matches but scores lower</td>\n</tr>\n<tr>\n<td><code>/unknown/deep/path</code></td>\n<td><code>not-found</code></td>\n<td>Nothing else matches — too many segments for <code>:page</code>, no prefix match for static routes. <code>*</code> catches everything as last resort</td>\n</tr>\n</tbody></table>\n<p>Tiebreakers when scores are equal: specificity (ratio of static to total segments), then insertion order in the routes array.</p>\n"
  },
  {
    "id": "lifecycle",
    "title": "Lifecycle",
    "order": 4,
    "html": "<h2>Lifecycle</h2>\n<p>Every route can declare <code>enter</code> and <code>leave</code>. Both receive the current route context and an <code>AbortSignal</code>. They run sequentially — the next callback waits for the previous one to resolve.</p>\n<ul>\n<li><strong><code>enter</code></strong> — Runs before the route becomes active. Use it to fetch data, check permissions, or run side effects.</li>\n<li><strong><code>leave</code></strong> — Runs before navigating away. Use it for cleanup, unsaved-changes prompts, or analytics.</li>\n</ul>\n<p>Return <code>false</code> from either callback to cancel the navigation. The URL does not change, the current route stays active. Any other return value allows the navigation to proceed.</p>\n<h3>Enter Callback</h3>\n<pre><code class=\"language-typescript\">import Router from &#39;lit-router&#39;;\n\nclass App extends LitElement {\n  _router = new Router(this, [\n    {\n      path: &#39;/dashboard&#39;,\n      enter: () =&gt; {\n        if (!isLoggedIn()) return false;\n      },\n      render: () =&gt; html`&lt;dashboard-page&gt;&lt;/dashboard-page&gt;`,\n    },\n    {\n      path: &#39;/reports/:id&#39;,\n      enter: async ({ params, signal }) =&gt; {\n        const response = await fetch(`/api/reports/${params.id}`, { signal });\n        if (!response.ok) return false;\n        this._report = await response.json();\n      },\n      render: ({ params }) =&gt; html`\n        &lt;report-page id=${params.id} .data=${this._report}&gt;&lt;/report-page&gt;`,\n    },\n  ]);\n}\n</code></pre>\n<p>The <code>enter</code> callback signature:</p>\n<pre><code class=\"language-typescript\">enter: (context: {\n  params: Record&lt;string, string&gt;, // URL path parameters matched by next route\n  extraParams: Record&lt;string, any&gt;, // accumulated data from upstream callers (set via `navigate()` or `push()` options)\n  searchParams: Record&lt;string, string&gt;,  // next route URL query string\n  hash: string, // URL hash fragment (without `#`)\n  signal: AbortSignal, // An abortsignal that can abort the navegation\n  pathname: string, // next pathname\n  route: Route, // the matched `Route` instance\n}) =&gt; Promise&lt;boolean | void&gt; | boolean | void\n</code></pre>\n<ul>\n<li><code>signal</code> is aborted if a new navigation supersedes the current one (e.g. rapid clicks) or the host disconnects from the DOM</li>\n<li>Use <code>signal</code> to cancel in-flight fetches, timers, or subscriptions</li>\n</ul>\n<h3>Leave Callback</h3>\n<pre><code class=\"language-typescript\">{\n  path: &#39;/editor/:id&#39;,\n  leave: async ({ params }) =&gt; {\n    if (this._hasUnsavedChanges) {\n      return confirm(&#39;Discard changes?&#39;);\n    }\n  },\n  render: () =&gt; html`&lt;editor-page&gt;&lt;/editor-page&gt;`,\n}\n</code></pre>\n<p>The <code>leave</code> callback signature:</p>\n<pre><code class=\"language-typescript\">leave: (context: {\n  params: Record&lt;string, string&gt;, // URL path parameters matched by current route\n  extraParams: Record&lt;string, any&gt;, // accumulated data from upstream callers (set via `navigate()` or `push()` options)\n  searchParams: Record&lt;string, string&gt;, // URL query string\n  hash: string, // URL hash fragment (without `#`)\n  signal: AbortSignal, // An abortsignal that can abort the navegation\n}) =&gt; Promise&lt;boolean | void&gt; | boolean | void\n</code></pre>\n<p>Leave callbacks fire bottom-up — deepest child first, then its ancestors. If any returns <code>false</code>, the navigation is cancelled and no further leave callbacks run.</p>\n<h3>Render Callback</h3>\n<p>The <code>render</code> callback fires after <code>enter</code> succeeds. It receives the merged route context and returns a Lit <code>TemplateResult</code>.</p>\n<p><strong>render signature:</strong></p>\n<pre><code class=\"language-typescript\">render: (context: {\n  params: Record&lt;string, string&gt;, // URL path parameters matched by this route\n  extraParams: Record&lt;string, any&gt;, // accumulated data from upstream callers (set via `navigate()` or `push()` options)\n  searchParams: Record&lt;string, string&gt;, // current URL query string\n  hash: string, // URL hash fragment (without `#`)\n  route: Route, // the `Route` instance itself\n}) =&gt; TemplateResult | nothing | null\n</code></pre>\n<h3>Navigation Order</h3>\n<p>When navigating from <code>/editor/1</code> to <code>/dashboard</code>:</p>\n<ol>\n<li><strong>Leave</strong> of <code>/editor/:id</code> fires (deepest child → ancestors)</li>\n<li><strong>Enter</strong> of <code>/dashboard</code> fires</li>\n<li>If any callback returns <code>false</code>, navigation is cancelled and the URL does not change</li>\n<li>If all callbacks pass, the new route renders and window history is updated</li>\n</ol>\n<pre class=\"mermaid\">sequenceDiagram\n    participant U as User\n    participant R as Router\n    participant L as Leave Callback\n    participant E as Enter Callback\n    participant P as Render\n\n    U->>R: Navigate to /dashboard\n    R->>L: Run leave on current route\n    L-->>R: proceed\n    R->>E: Run enter on /dashboard\n    alt enter succeeds\n        E-->>R: proceed\n        R->>P: Render matched component\n        P-->>U: Page updated\n    else enter returns false\n        E-->>R: cancel\n        R-->>U: Navigation cancelled\n    end</pre>\n<blockquote>\n<p><strong>Note:</strong> Leave callbacks are skipped during browser-initiated navigation (popstate, initial load) — the browser already navigated away. The skip also applies on the fast-path when the same route is matched with the same params.</p>\n</blockquote>\n"
  },
  {
    "id": "nested-syntax",
    "title": "Nested Routing",
    "order": 5,
    "html": "<h2>Nested Routing</h2>\n<p>lit-router nests routes through multiple <code>Routes</code> controllers connected in the DOM tree. A parent controller delegates the unmatched portion of the URL — the tail group — to a child controller inside its outlet.</p>\n<h3>How Tail Propagation Works</h3>\n<p>A route ending with <code>*</code> captures everything after the matched static prefix as its tail group. When a child <code>Routes</code> controller connects inside the parent&#39;s outlet, the parent forwards the tail group to the child. The child then tries to match this tail against its own routes.</p>\n<pre><code>URL: /admin/users/42\n\nRouter matches /admin/*  →  tail group = &quot;/users/42&quot;\n  └─ Renders &lt;admin-layout&gt;\n       └─ Routes matches /users/:id  →  params.id = &quot;42&quot;\n            └─ Renders &lt;user-detail id=&quot;42&quot;&gt;\n</code></pre>\n<h3>Defining Nested Routes</h3>\n<p>The root <code>Router</code> declares the wildcard. The child component owns its own <code>Routes</code> controller. No <code>children</code> array — nesting is structural, via the DOM.</p>\n<pre><code class=\"language-typescript\">import { LitElement, html } from &#39;lit&#39;;\nimport Router, { Routes } from &#39;lit-router&#39;;\n\nclass AppRoot extends LitElement {\n  _router = new Router(this, [\n    { path: &#39;/&#39;,          render: () =&gt; html`&lt;home-page&gt;&lt;/home-page&gt;` },\n    { path: &#39;/admin/*&#39;,   render: () =&gt; html`&lt;admin-layout&gt;&lt;/admin-layout&gt;` },\n    { path: &#39;*&#39;,          render: () =&gt; html`&lt;not-found&gt;&lt;/not-found&gt;` },\n  ]);\n\n  render() {\n    return html`&lt;main&gt;${this._router.outlet()}&lt;/main&gt;`;\n  }\n}\ncustomElements.define(&#39;app-root&#39;, AppRoot);\n\nclass AdminLayout extends LitElement {\n  _routes = new Routes(this, [\n    { path: &#39;/&#39;,          render: () =&gt; html`&lt;admin-dashboard&gt;&lt;/admin-dashboard&gt;` },\n    { path: &#39;/users&#39;,     render: () =&gt; html`&lt;admin-users&gt;&lt;/admin-users&gt;` },\n    { path: &#39;/users/:id&#39;, render: ({ params }) =&gt;\n      html`&lt;user-detail id=${params.id}&gt;&lt;/user-detail&gt;` },\n    { path: &#39;/settings&#39;,  render: () =&gt; html`&lt;admin-settings&gt;&lt;/admin-settings&gt;` },\n    { path: &#39;*&#39;,          render: () =&gt; html`&lt;not-found&gt;&lt;/not-found&gt;` },\n  ]);\n\n  render() {\n    return html`\n      &lt;aside&gt;\n        &lt;a href=&quot;/admin&quot;&gt;Dashboard&lt;/a&gt;\n        &lt;a href=&quot;/admin/users&quot;&gt;Users&lt;/a&gt;\n        &lt;a href=&quot;/admin/settings&quot;&gt;Settings&lt;/a&gt;\n      &lt;/aside&gt;\n      &lt;main&gt;${this._routes.outlet()}&lt;/main&gt;\n    `;\n  }\n}\ncustomElements.define(&#39;admin-layout&#39;, AdminLayout);\n</code></pre>\n<p>The <code>outlet()</code> method renders a <code>&lt;lit-router-outlet&gt;</code> custom element that projects children into the Light DOM. This allows nested <code>Routes</code> controllers to discover each other through DOM events — no manual wiring, no prop drilling.</p>\n<h3>Guards on Parent Routes</h3>\n<p>Parent routes can use <code>enter</code> to protect all child routes at once. If the parent&#39;s <code>enter</code> returns <code>false</code>, the children never evaluate.</p>\n<pre><code class=\"language-typescript\">{\n  path: &#39;/admin/*&#39;,\n  enter: () =&gt; isAdmin() || false,\n  render: () =&gt; html`&lt;admin-layout&gt;&lt;/admin-layout&gt;`,\n}\n</code></pre>\n<h3>Common Mistake</h3>\n<p>Forgetting the <code>*</code> on the parent route prevents the tail group from propagating. The child receives only the matched static portion and cannot match deeper paths.</p>\n<pre><code class=\"language-typescript\">// Wrong — /admin/settings never reaches the child\n{ path: &#39;/admin&#39;, render: () =&gt; html`&lt;admin-layout&gt;&lt;/admin-layout&gt;` }\n\n// Correct — wildcard captures the tail\n{ path: &#39;/admin/*&#39;, render: () =&gt; html`&lt;admin-layout&gt;&lt;/admin-layout&gt;` }\n</code></pre>\n<p>Named wildcards (<code>:param*</code>) are not compatible with nested routing. Use plain <code>*</code> for routes that have child <code>Routes</code> controllers.</p>\n<h3>Navigation Flow</h3>\n<pre class=\"mermaid\">sequenceDiagram\n    participant U as User\n    participant R as Router\n    participant AL as AdminLayout\n    participant C as Child Routes\n\n    U->>R: Navigate to /admin/users/42\n    R->>R: Match /admin/*<br/> extract tail: /users/42\n    R->>AL: Render AdminLayout\n    AL->>C: Forward tail /users/42\n    C->>C: Match /users/:id<br/> params.id = 42\n    C-->>U: Render UserDetail</pre>\n"
  },
  {
    "id": "navigation-controller",
    "title": "Navigation Controller",
    "order": 6,
    "html": "<h2>Navigation Controller</h2>\n<p><code>Navigation</code> is a Lit Reactive Controller that gives any component access to the router without being a route itself. It discovers the nearest <code>Router</code> and <code>Routes</code> via DOM events — no props, context providers, or manual wiring.</p>\n<pre><code class=\"language-typescript\">import { Navigation } from &#39;lit-router&#39;;\n\nclass UserProfile extends LitElement {\n  nav = new Navigation(this);\n}\n</code></pre>\n<p>The controller registers itself on the host via <code>addController(this)</code>. On connect, it dispatches <code>RouterAcknowledgeEvent</code> and <code>RoutesAcknowledgeEvent</code> which bubble up to the nearest <code>Router</code> and <code>Routes</code>. A subscription to the router delivers state changes that the controller re-dispatches as <code>Navigation.event</code> on the host.</p>\n<h3>Reactive Properties</h3>\n<p>All properties read from the router and reflect the current navigation state.</p>\n<pre><code class=\"language-typescript\">this.nav.url          // &quot;/users/42?tab=posts#bio&quot;\nthis.nav.pathname     // &quot;/users/42&quot;\nthis.nav.params       // { id: &quot;42&quot; }\nthis.nav.searchParams // { tab: &quot;posts&quot; }  — also has a setter\nthis.nav.hash         // &quot;bio&quot;             — also has a setter\nthis.nav.extraParams  // { draft: &quot;abc&quot; }\nthis.nav.routeName    // &quot;user-detail&quot;     — from route config name\n</code></pre>\n<p>The <code>searchParams</code> and <code>hash</code> setters update the URL bar without changing the path. The router re-renders the host automatically.</p>\n<h3><code>navigate(pathname, options?)</code></h3>\n<p>Navigate to an absolute application path. Updates the browser URL bar via <code>history.pushState</code>.</p>\n<pre><code class=\"language-typescript\">this.nav.navigate(&#39;/dashboard&#39;);\nthis.nav.navigate(&#39;/users/42&#39;, { hash: &#39;activity&#39; });\nthis.nav.navigate(&#39;/search&#39;, { searchParams: { q: &#39;lit&#39; } });\nthis.nav.navigate(&#39;/editor&#39;, { draftId: &#39;abc-123&#39; });\n</code></pre>\n<p>Any extra keys in <code>options</code> beyond <code>searchParams</code> and <code>hash</code> are forwarded as <code>extraParams</code> — accessible in <code>enter</code>, <code>leave</code>, and <code>render</code> callbacks of the target route.</p>\n<h3><code>push(pathname, options?)</code></h3>\n<p>Navigates deeper into a child route tree. Appends a relative path to the current route&#39;s matched segment and activates the matching child route.</p>\n<p>Two conditions must be met:</p>\n<ol>\n<li>The current route path ends with <code>*</code>. The wildcard captures the URL tail that the child matches against.</li>\n<li>At least one child <code>Routes</code> controller exists in the DOM inside the parent&#39;s outlet.</li>\n</ol>\n<p>When you call <code>push(&quot;./posts&quot;)</code>, the controller resolves the relative path against the current route, merges <code>extraParams</code> from the current state with any new ones, and calls <code>navigate()</code>. A new <code>history.pushState</code> entry is created — the browser back button retraces each push.</p>\n<pre><code class=\"language-typescript\">class AdminLayout extends LitElement {\n  nav = new Navigation(this);\n  _tabs = new Routes(this, [\n    { path: &#39;/posts&#39;,   render: () =&gt; html`&lt;posts-tab&gt;&lt;/posts-tab&gt;` },\n    { path: &#39;/users&#39;,   render: () =&gt; html`&lt;users-tab&gt;&lt;/users-tab&gt;` },\n    { path: &#39;/reports&#39;, render: () =&gt; html`&lt;reports-tab&gt;&lt;/reports-tab&gt;` },\n    { path: &#39;/&#39;,        render: () =&gt; html`&lt;dashboard-tab&gt;&lt;/dashboard-tab&gt;` },\n  ]);\n\n  constructor() {\n    super();\n    this.addEventListener(Navigation.event, () =&gt; this.requestUpdate());\n  }\n\n  render() {\n    const path = this.nav.pathname;\n    const active = path.startsWith(&#39;/admin/posts&#39;) ? &#39;posts&#39;\n                 : path.startsWith(&#39;/admin/users&#39;) ? &#39;users&#39;\n                 : path.startsWith(&#39;/admin/reports&#39;) ? &#39;reports&#39;\n                 : &#39;dashboard&#39;;\n\n    return html`\n      &lt;nav&gt;\n        &lt;button ?active=${active === &#39;posts&#39;}   @click=${() =&gt; this.nav.push(&#39;./posts&#39;)}&gt;Posts&lt;/button&gt;\n        &lt;button ?active=${active === &#39;users&#39;}   @click=${() =&gt; this.nav.push(&#39;./users&#39;)}&gt;Users&lt;/button&gt;\n        &lt;button ?active=${active === &#39;reports&#39;} @click=${() =&gt; this.nav.push(&#39;./reports&#39;)}&gt;Reports&lt;/button&gt;\n      &lt;/nav&gt;\n      &lt;main&gt;${this._tabs.outlet()}&lt;/main&gt;\n    `;\n  }\n}\n</code></pre>\n<p>URL behavior:</p>\n<ul>\n<li><code>/admin</code> → <code>DashboardTab</code> renders (<code>/</code> matches the empty tail)</li>\n<li>Click &quot;Posts&quot; → <code>push(&quot;./posts&quot;)</code> → URL becomes <code>/admin/posts</code></li>\n<li>Click &quot;Users&quot; → <code>push(&quot;./users&quot;)</code> → URL becomes <code>/admin/users</code></li>\n</ul>\n<p>Options:</p>\n<pre><code class=\"language-typescript\">this.nav.push(&#39;./detail&#39;, { preserveSearchParams: true });\nthis.nav.push(&#39;./editor&#39;, { draftId: &#39;abc-123&#39; });\n</code></pre>\n<p><code>push()</code> throws <code>InvalidNavigationError</code> if the current route does not end with <code>*</code> or if no child <code>Routes</code> controllers are present.</p>\n<h3><code>pop(options?)</code></h3>\n<p>Navigates back out of a child route toward its parent. Strips the current tail segment from the URL.</p>\n<p>When called, the controller checks if the current route has a tail group. If the URL is <code>/admin/posts</code> and the route <code>/admin/*</code> captured tail <code>/posts</code>, the controller navigates to <code>/admin</code> (the parent&#39;s link without the tail). If the current route has no tail but has a parent <code>Routes</code> controller, it navigates to the parent&#39;s link. If neither applies, it does nothing.</p>\n<p>Like <code>push()</code>, <code>pop()</code> creates a new <code>history.pushState</code> entry — it does not call <code>history.back()</code>.</p>\n<pre><code class=\"language-typescript\">import { LitElement, html, nothing } from &#39;lit&#39;;\n\nclass ArticleDetail extends LitElement {\n  nav = new Navigation(this);\n  _modal = new Routes(this, [\n    {\n      path: &#39;/:slug&#39;,\n      enter: async ({ params, signal }) =&gt; {\n        this._article = await fetchArticle(params.slug, { signal });\n        this.dialog.showModal();\n      },\n      render: ({ params }) =&gt;\n        html`&lt;article-dialog .article=${this._article}&gt;&lt;/article-dialog&gt;`,\n    },\n    {\n      path: &#39;*&#39;,\n      render: () =&gt; { this.dialog.close(); return nothing; },\n    },\n  ]);\n\n  private _onDialogClose = () =&gt; {\n    if (this.dialog.returnValue === &#39;dismiss&#39;) {\n      this.nav.pop();\n    }\n  };\n\n  render() {\n    return html`\n      &lt;dialog ${ref(this.dialog)} @close=${this._onDialogClose}&gt;\n        ${this._modal.outlet()}\n      &lt;/dialog&gt;\n    `;\n  }\n}\n</code></pre>\n<p>Flow:</p>\n<ol>\n<li>User is at <code>/articles</code>, clicks article link → <code>push(&quot;./my-post&quot;)</code></li>\n<li>URL becomes <code>/articles/my-post</code>, <code>enter</code> fires, <code>&lt;dialog&gt;</code> opens</li>\n<li>User dismisses dialog → <code>close</code> event → <code>pop()</code></li>\n<li>URL returns to <code>/articles</code>, dialog closes</li>\n</ol>\n<p>Options:</p>\n<pre><code class=\"language-typescript\">this.nav.pop({ preserveSearchParams: true });\nthis.nav.pop({ searchParams: { tab: &#39;settings&#39; } });\nthis.nav.pop({ hash: &#39;section-header&#39; });\n</code></pre>\n<h3><code>goback()</code></h3>\n<p>Equivalent to <code>history.back()</code>.</p>\n<pre><code class=\"language-typescript\">this.nav.goback();\n</code></pre>\n<h3><code>Navigation.event</code></h3>\n<p>The controller dispatches a <code>CustomEvent</code> with type <code>&quot;navigation&quot;</code> on the host element whenever route state changes. The event <code>detail</code> contains <code>prev</code> and <code>next</code> snapshots.</p>\n<pre><code class=\"language-typescript\">class Breadcrumb extends LitElement {\n  nav = new Navigation(this);\n\n  constructor() {\n    super();\n    this.addEventListener(Navigation.event, () =&gt; this.requestUpdate());\n  }\n\n  render() {\n    const segments = this.nav.pathname.split(&#39;/&#39;).filter(Boolean);\n    return html`\n      &lt;nav&gt;\n        &lt;a href=&quot;/&quot;&gt;Home&lt;/a&gt;\n        ${segments.map((s, i) =&gt; {\n          const href = &#39;/&#39; + segments.slice(0, i + 1).join(&#39;/&#39;);\n          return html`&lt;span&gt; / &lt;/span&gt;&lt;a href=${href}&gt;${s}&lt;/a&gt;`;\n        })}\n      &lt;/nav&gt;\n    `;\n  }\n}\n</code></pre>\n<p>For conditional re-rendering based on specific params:</p>\n<pre><code class=\"language-typescript\">this.addEventListener(Navigation.event, ({ detail: { prev, next } }) =&gt; {\n  if (next.params.id !== prev.params.id) {\n    this.fetchData(next.params.id);\n  }\n});\n</code></pre>\n<p>The subscription delivers the current state immediately upon registration — the first event fires with <code>prev</code> as <code>undefined</code>.</p>\n<h3><code>hasFocus()</code></h3>\n<p>Returns <code>true</code> when the current route has child routes but no active tail. Useful for active-state styling on navigation elements.</p>\n<pre><code class=\"language-typescript\">class NavLink extends LitElement {\n  nav = new Navigation(this);\n\n  constructor() {\n    super();\n    this.addEventListener(Navigation.event, () =&gt; this.requestUpdate());\n  }\n\n  render() {\n    return html`\n      &lt;a href=${this.href} class=${this.nav.hasFocus() ? &#39;active&#39; : &#39;&#39;}&gt;\n        &lt;slot&gt;&lt;/slot&gt;\n      &lt;/a&gt;\n    `;\n  }\n}\n</code></pre>\n<h3><code>link(pathname?)</code></h3>\n<p>Builds a relative URL against the current route without navigating.</p>\n<pre><code class=\"language-typescript\">const childUrl = this.nav.link(&#39;./settings&#39;);  // &quot;/admin/settings&quot;\nconst parentUrl = this.nav.link();              // &quot;/admin&quot;\n</code></pre>\n<p>Throws <code>InvalidNavigationError</code> if child routes exist and <code>pathname</code> does not start with <code>./</code>.</p>\n<h3>Error Handling</h3>\n<p><code>navigate()</code>, <code>push()</code>, and <code>pop()</code> return Promises. Wrap calls in <code>try/catch</code> to handle navigation failures:</p>\n<pre><code class=\"language-typescript\">async goToAdmin() {\n  try {\n    await this.nav.push(&#39;./settings&#39;);\n  } catch (err) {\n    console.error(&#39;Navigation failed:&#39;, err.message);\n  }\n}\n</code></pre>\n<p>For errors from <code>&lt;a&gt;</code> clicks, listen to <code>@lit-router-error</code> on a parent element:</p>\n<pre><code class=\"language-typescript\">render() {\n  return html`\n    &lt;section @lit-router-error=${(e) =&gt; console.error(e.detail.error.message)}&gt;\n      &lt;a href=&quot;/broken-route&quot;&gt;Broken Link&lt;/a&gt;\n    &lt;/section&gt;\n  `;\n}\n</code></pre>\n"
  },
  {
    "id": "path-syntax",
    "title": "Advanced Path Syntaxes",
    "order": 7,
    "html": "<h1>Advanced Path Syntaxes</h1>\n<h2>Path Patterns</h2>\n<p>lit-router compiles route paths into regular expressions at construction time. The compiler supports four segment types, ranked by specificity.</p>\n<table>\n<thead>\n<tr>\n<th>Pattern</th>\n<th>Matches</th>\n<th>Examples</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Static</td>\n<td>Exact literal segment</td>\n<td><code>/about</code>, <code>/users/profile</code></td>\n</tr>\n<tr>\n<td><code>:param</code></td>\n<td>Any single non-slash segment</td>\n<td><code>/users/:id</code> matches <code>/users/42</code></td>\n</tr>\n<tr>\n<td><code>:param?</code></td>\n<td>Zero or one non-slash segment</td>\n<td><code>/search/:query?</code> matches <code>/search</code> and <code>/search/term</code></td>\n</tr>\n<tr>\n<td><code>*</code></td>\n<td>Everything after the prefix</td>\n<td><code>/admin/*</code> matches <code>/admin</code>, <code>/admin/settings/users</code></td>\n</tr>\n<tr>\n<td><code>:param*</code></td>\n<td>Named wildcard capture</td>\n<td><code>/files/:path*</code> captures <code>docs/readme.md</code> into <code>params.path</code></td>\n</tr>\n</tbody></table>\n<p>Trailing slashes are tolerated — every compiled pattern ends with <code>/?$</code>. Matching is case-sensitive.</p>\n<h2>Scoring Priority</h2>\n<p>Routes are ranked by a numeric score before matching. Higher scores are tried first, regardless of definition order.</p>\n<table>\n<thead>\n<tr>\n<th>Segment type</th>\n<th>Weight</th>\n</tr>\n</thead>\n<tbody><tr>\n<td>Static</td>\n<td>1000</td>\n</tr>\n<tr>\n<td>Dynamic (<code>:param</code>)</td>\n<td>100</td>\n</tr>\n<tr>\n<td>Optional (<code>:param?</code>)</td>\n<td>10</td>\n</tr>\n<tr>\n<td>Depth (per segment)</td>\n<td>1</td>\n</tr>\n<tr>\n<td>Wildcard (<code>*</code>)</td>\n<td>-50</td>\n</tr>\n</tbody></table>\n<p>Static routes always outrank dynamic ones. A route <code>/foo/bar</code> scores higher than <code>/foo/:param</code> even if the latter is defined first.</p>\n<pre><code class=\"language-typescript\">class App extends LitElement {\n  _router = new Router(this, [\n    { name: &#39;dynamic&#39;, path: &#39;/foo/:param&#39;, render: () =&gt; html`&lt;dynamic-page&gt;&lt;/dynamic-page&gt;` },\n    { name: &#39;static&#39;,  path: &#39;/foo/bar&#39;,    render: () =&gt; html`&lt;static-page&gt;&lt;/static-page&gt;` },\n  ]);\n}\n</code></pre>\n<ul>\n<li>Navigating to <code>/foo/blue</code> matches <code>dynamic</code> — <code>:param</code> captures <code>&quot;blue&quot;</code></li>\n<li>Navigating to <code>/foo/bar</code> matches <code>static</code> — the higher score wins over <code>dynamic</code></li>\n</ul>\n<h2>Wildcard</h2>\n<p>A trailing <code>*</code> matches zero or more remaining path segments. Use it to capture unknown sub-paths or enable nested routing.</p>\n<pre><code class=\"language-typescript\">class App extends LitElement {\n  _router = new Router(this, [\n    { path: &#39;/&#39;,              render: () =&gt; html`&lt;home-page&gt;&lt;/home-page&gt;` },\n    { path: &#39;/dashboard&#39;,     render: () =&gt; html`&lt;dashboard-page&gt;&lt;/dashboard-page&gt;` },\n    { path: &#39;/user/account&#39;,  render: () =&gt; html`&lt;account-page&gt;&lt;/account-page&gt;` },\n    { path: &#39;*&#39;,              render: () =&gt; html`&lt;not-found&gt;&lt;/not-found&gt;` },\n  ]);\n}\n</code></pre>\n<p>Navigating to <code>/user</code> matches <code>*</code> — the static route <code>/user/account</code> does not match because it requires the full segment. The wildcard acts as a catch-all 404.</p>\n<p>A named wildcard <code>/:path*</code> captures the tail into <code>params</code>:</p>\n<pre><code class=\"language-typescript\">{\n  path: &#39;/:missingUrl*&#39;,\n  render: ({ params }) =&gt;\n    html`&lt;not-found .url=${params.missingUrl}&gt;&lt;/not-found&gt;`,\n}\n</code></pre>\n<blockquote>\n<p><strong>Note:</strong> Named wildcards (<code>:param*</code>) capture tail segments but are not compatible with nested routing. Use plain <code>*</code> for routes that have child <code>Routes</code> controllers.</p>\n</blockquote>\n"
  },
  {
    "id": "router-api",
    "title": "Router Instance API",
    "order": 8,
    "html": "<h2>Getting the Router Reference</h2>\n<p>Every component with a <code>Navigation</code> controller can access the root <code>Router</code> instance via <code>this.nav.router</code>. Components that own the <code>Router</code> directly already have the reference.</p>\n<pre><code class=\"language-typescript\">const router = this.nav.router;  // from Navigation controller\nconst router = this._router;     // from owning component\n</code></pre>\n<h2><code>router.subscribe(callback)</code></h2>\n<p>Subscribes to route state changes. The callback receives <code>{ eventName, prev, next }</code> on every navigation. The current state is delivered immediately upon subscription — late subscribers don&#39;t miss the initial route.</p>\n<pre><code class=\"language-typescript\">import Router from &#39;lit-router&#39;;\n\nclass AnalyticsTracker extends LitElement {\n  _router = new Router(this, [\n    { path: &#39;/&#39;, render: () =&gt; html`&lt;home-page&gt;&lt;/home-page&gt;` },\n  ]);\n\n  constructor() {\n    super();\n    this._router.subscribe(({ next }) =&gt; {\n      console.log(`Route changed to ${next.pathname}`);\n      // Fire analytics event, update page title, etc.\n    });\n  }\n}\n</code></pre>\n<p>The callback signature:</p>\n<pre><code class=\"language-typescript\">subscribe(callback: (detail: {\n  eventName: &quot;location-changed&quot; | &quot;location-changing&quot;,\n  prev: { pathname, params, searchParams, hash } | undefined,\n  next: { pathname, params, searchParams, hash },\n}) =&gt; void): () =&gt; void\n</code></pre>\n<p>Returns an unsubscribe function. Call it to stop receiving updates — useful in <code>hostDisconnected()</code>.</p>\n<pre><code class=\"language-typescript\">const unsub = this._router.subscribe(this._onRouteChange);\n// later:\nunsub();\n</code></pre>\n<p><code>prev</code> is <code>undefined</code> on the first delivery (no previous route exists).</p>\n<h2><code>router.replaceState(options)</code></h2>\n<p>Updates the current URL&#39;s query string, hash, or extra state without triggering navigation. <code>enter</code> and <code>leave</code> callbacks do not fire. The URL bar updates silently via <code>history.replaceState</code>.</p>\n<pre><code class=\"language-typescript\">// Update a filter without pushing to history\nthis._router.replaceState({ searchParams: { tab: &#39;active&#39;, page: &#39;1&#39; } });\n\n// Set a hash anchor\nthis._router.replaceState({ hash: &#39;comments&#39; });\n\n// Store transient UI state\nthis._router.replaceState({ extraParams: { sidebarOpen: true } });\n</code></pre>\n<p>Use <code>replaceState</code> for UI state that should survive a page refresh but shouldn&#39;t create history entries — filter panels, tab selections, scroll positions, collapsed sections. For user-initiated navigation that should appear in browser history, use <code>navigate()</code> instead.</p>\n<h2><code>router.buildUrl(pathname)</code></h2>\n<p>Constructs a full URL string for a given pathname, resolved against the current route. Does not navigate.</p>\n<pre><code class=\"language-typescript\">const shareUrl = this._router.buildUrl(&#39;/reports/42&#39;);\n// &quot;https://app.example.com/reports/42&quot;\n\nconst filteredUrl = this._router.buildUrl(&#39;/search?q=lit&#39;);\n// &quot;https://app.example.com/search?q=lit&quot;\n</code></pre>\n<p>Use <code>buildUrl</code> for share buttons, copy-to-clipboard, <code>&lt;a&gt;</code> href generation in non-Lit contexts, or anywhere you need a string URL without triggering navigation.</p>\n<h2><code>goto()</code> vs <code>navigate()</code></h2>\n<p>Both resolve a pathname and activate the matching route. The difference is the URL bar.</p>\n<table>\n<thead>\n<tr>\n<th></th>\n<th><code>goto(pathname, options?)</code></th>\n<th><code>navigate(pathname, options?)</code></th>\n</tr>\n</thead>\n<tbody><tr>\n<td>URL bar</td>\n<td>Does <strong>not</strong> update</td>\n<td>Calls <code>history.pushState</code></td>\n</tr>\n<tr>\n<td>Use case</td>\n<td>Internal routing, initial load, redirects inside enter</td>\n<td>User-facing navigation</td>\n</tr>\n<tr>\n<td>Returns</td>\n<td><code>Promise&lt;boolean&gt;</code> — <code>false</code> if cancelled</td>\n<td><code>Promise&lt;void&gt;</code></td>\n</tr>\n</tbody></table>\n<pre><code class=\"language-typescript\">// navigate() — user clicks a link or button\nthis._router.navigate(&#39;/dashboard&#39;);\n\n// goto() — redirect inside an enter callback\n{\n  path: &#39;/admin/*&#39;,\n  enter: async () =&gt; {\n    if (!isLoggedIn) {\n      await this._router.goto(&#39;/login&#39;);\n      return false;\n    }\n  },\n  render: () =&gt; html`&lt;admin-layout&gt;&lt;/admin-layout&gt;`,\n}\n</code></pre>\n<p><code>goto()</code> returns <code>false</code> when navigation is cancelled (enter/leave returned false). <code>navigate()</code> resolves silently when cancelled.</p>\n<h2>Redirect Pattern</h2>\n<p>The correct way to redirect inside an <code>enter</code> callback is to call <code>goto()</code> followed by <code>return false</code>. This tells the router: stop processing the current route, and don&#39;t update the URL bar twice.</p>\n<pre><code class=\"language-typescript\">{\n  path: &#39;/dashboard&#39;,\n  enter: async () =&gt; {\n    if (!auth.isLoggedIn) {\n      await this._router.goto(&#39;/login&#39;);\n      return false;          // required — cancel this route\n    }\n  },\n  render: () =&gt; html`&lt;dashboard-page&gt;&lt;/dashboard-page&gt;`,\n}\n</code></pre>\n<p>Calling <code>navigate()</code> inside <code>enter</code> also works thanks to a navId guard that detects the redirect and skips the outer <code>pushState</code>. But <code>goto()</code> is the intentional API for this case — it changes the route state without touching the URL bar, and the outer <code>navigate()</code> call (from the anchor click or programmatic trigger) will push the final, correct URL.</p>\n<h2>Custom Events</h2>\n<p>The <code>Router</code> dispatches events on <code>window</code> during navigation. Components anywhere in the DOM tree can listen for them.</p>\n<h3><code>RouterLocationChangingEvent</code> (<code>lit-router-location-changing</code>)</h3>\n<p>Fires <strong>before</strong> navigation starts. Cancelable — calling <code>e.preventDefault()</code> stops the navigation.</p>\n<pre><code class=\"language-typescript\">window.addEventListener(&#39;lit-router-location-changing&#39;, (e) =&gt; {\n  const { currentPathname, pathname } = e.detail;\n\n  if (hasUnsavedChanges() &amp;&amp; !confirm(&#39;Discard changes?&#39;)) {\n    e.preventDefault();       // cancel navigation\n  } else {\n    showLoadingIndicator();   // prepare for the transition\n  }\n});\n</code></pre>\n<p>Event detail: <code>{ currentPathname, pathname, extraParams, searchParams, hash }</code>.</p>\n<h3><code>RouterLocationChangedEvent</code> (<code>lit-router-location-changed</code>)</h3>\n<p>Fires <strong>after</strong> navigation completes successfully.</p>\n<pre><code class=\"language-typescript\">window.addEventListener(&#39;lit-router-location-changed&#39;, (e) =&gt; {\n  const { pathname, params, searchParams } = e.detail;\n  hideLoadingIndicator();\n  document.title = `App — ${pathname}`;\n});\n</code></pre>\n<p>Event detail: <code>{ pathname, params, extraParams, searchParams, hash }</code>.</p>\n<h3><code>RouterNavigationErrorEvent</code> (<code>lit-router-error</code>)</h3>\n<p>Fires on the <code>&lt;a&gt;</code> element when an anchor click causes a non-<code>InvalidNavigationError</code>. Already covered in <a href=\"#\">Anchor Links</a> — use <code>try/catch</code> for programmatic errors.</p>\n<h2>Error Types</h2>\n<h3><code>InvalidNavigationError</code></h3>\n<p>Thrown when navigation cannot proceed: cancelled by enter/leave, no routes defined, push() called on a non-wildcard route.</p>\n<pre><code class=\"language-typescript\">try {\n  await this.nav.push(&#39;./child&#39;);\n} catch (err) {\n  if (err instanceof InvalidNavigationError) {\n    // err.metadata.reason — &quot;leave-callback&quot; | &quot;enter-callback&quot; | &quot;no-routes&quot;\n    // err.metadata.operation — &quot;push&quot; | &quot;navigate&quot; | &quot;goto&quot; | &quot;link&quot;\n    // err.metadata.pathname — target path that failed\n    // err.metadata.currentRoute — the Route that was active\n  }\n}\n</code></pre>\n<h3><code>RouteNotFoundError</code></h3>\n<p>Thrown when no route matches the target pathname. The catch-all <code>*</code> route prevents this — it always matches.</p>\n<pre><code class=\"language-typescript\">try {\n  await this.nav.navigate(&#39;/nonexistent&#39;);\n} catch (err) {\n  if (err instanceof RouteNotFoundError) {\n    // err.metadata.targetPath — the path that didn&#39;t match\n    // err.metadata.currentPathname — current location\n  }\n}\n</code></pre>\n<blockquote>\n<p><strong>Note:</strong> If you define a <code>*</code> catch-all route, <code>RouteNotFoundError</code> is never thrown. It only surfaces when the router has no fallback and the URL doesn&#39;t match any route.</p>\n</blockquote>\n"
  }
];
